.sidebar .author__name {
  @include breakpoint($medium) {
    font-size: $type-size-4;
  }
  font-family: $sans-serif;
  font-size: $type-size-4;
}

.author__bio {
  margin: 0;
  color: mix(#fff, $text-color, 18%);

  @include breakpoint($large) {
    margin-top: 10px;
    margin-bottom: 18px;
  }
}

.author__tagline {
  margin-bottom: 1em;
  padding: 0.75rem;
  border-left: 3px solid #d84315;
  border-radius: $border-radius;
  background: rgba(216, 67, 21, 0.06);
  color: mix(#fff, $text-color, 16%);
  white-space: normal !important;
}

.author__urls-wrapper {
  position: relative;
  display: table-cell;
  vertical-align: middle;
  font-family: $sans-serif;
  z-index: 10;
  position: relative;
  margin-left: auto;
  cursor: pointer;

  li:last-child {
    a {
      margin-bottom: 0;
    }
  }

  @include breakpoint($large) {
    display: block;
  }

  button {
    margin-bottom: 0;
    width: 120px;
    padding: 0.5em;
    @include breakpoint($large) {
      display: none;
    }
  }
}

.author__urls {
  display: none;
  position: absolute;
  right: 0;
  margin-top: 15px;
  padding: 10px;
  list-style-type: none;
  border: 1px solid $border-color;
  border-radius: $border-radius;
  background: #fff;
  z-index: -1;
  box-shadow: 0 0 10px rgba(#000, 0.25);
  cursor: default;

  @include breakpoint($large) {
    display: block;
    position: relative;
    margin: 0;
    padding: 0;
    border: 0;
    background: transparent;
    box-shadow: none;
  }

  &:before {
    display: block;
    content: "";
    position: absolute;
    top: -11px;
    left: calc(50% - 10px);
    width: 0;
    border-style: solid;
    border-width: 0 10px 10px;
    border-color: $border-color transparent;
    z-index: 0;

    @include breakpoint($large) {
      display: none;
    }
  }

  &:after {
    display: block;
    content: "";
    position: absolute;
    top: -10px;
    left: calc(50% - 10px);
    width: 0;
    border-style: solid;
    border-width: 0 10px 10px;
    border-color: #fff transparent;
    z-index: 1;

    @include breakpoint($large) {
      display: none;
    }
  }

  li {
    white-space: nowrap;
  }

  a {
    display: block;
    margin-bottom: 5px;
    padding-right: 5px;
    padding-top: 2px;
    padding-bottom: 2px;
    color: inherit;
    font-size: $type-size-5;
    text-decoration: none;

    i {
      color: #d96a34;
    }

    &:hover {
      color: #bf360c;
      text-decoration: none;
    }
  }
}

.author__urls li > i {
  color: #d96a34;
}

.author__urls_sm{
  padding: .25em;
  font-size: 1.75em;
  display: block;
  a {
    color: inherit;
    text-decoration: none;
    &:hover {
      text-decoration: underline;
    }
  }
  @include breakpoint($large) {
    display: none;
  }
}
